if (! function_exists('text_diff')) {
    function text_diff($old_text, $new_text)
    {
        // Simple line-by-line diff between two strings
        $old=isset($old_text)?(string)$old_text:'';
        $new=isset($new_text)?(string)$new_text:'';
        if($old===''&&$new==='')return['error'=>'At least one input required'];

        $old_lines=explode("\n",$old);
        $new_lines=explode("\n",$new);
        $old_map=array_flip($old_lines);
        $new_map=array_flip($new_lines);

        $additions=[];$removals=[];$unchanged=[];
        foreach($new_lines as$i=>$line){
            $t=trim($line);
            if($t==='')continue;
            if(isset($old_map[$line]))$unchanged[]=$line;
            else $additions[]=['line'=>$i+1,'content'=>$line];
        }
        foreach($old_lines as$i=>$line){
            $t=trim($line);
            if($t==='')continue;
            if(!isset($new_map[$line]))$removals[]=['line'=>$i+1,'content'=>$line];
        }

        // Compute simple similarity
        $total=count($additions)+count($removals)+count($unchanged);
        $similarity=$total>0?round(count($unchanged)/$total*100,1):100;

        return[
            'success'=>true,
            'old_lines'=>count($old_lines),
            'new_lines'=>count($new_lines),
            'additions'=>count($additions),
            'removals'=>count($removals),
            'unchanged'=>count($unchanged),
            'similarity_percent'=>$similarity,
            'added'=>$additions,
            'removed'=>$removals,
        ];
    }
